const { app } = require('@azure/functions');
const { CosmosClient } = require('@azure/cosmos');

const cosmosClient = new CosmosClient(process.env.COSMOS_CONNECTION_STRING);
const database = cosmosClient.database(process.env.COSMOS_DATABASE);
const container = database.container(process.env.COSMOS_CONTAINER);

const BATCH_SIZE = 100;
const MAX_EXECUTION_TIME = 570000;

app.http('batchDataProcessor', {
    methods: ['GET', 'POST'],
    authLevel: 'function',
    timeout: '00:10:00',
    handler: async (request, context) => {
        const startTime = Date.now();
        const results = {
            processed: 0,
            failed: 0,
            totalBatches: 0,
            errors: [],
            startTime: new Date(startTime).toISOString(),
            status: 'in-progress'
        };

        try {
            context.log('Starting batch data processing');
            
            const querySpec = {
                query: 'SELECT * FROM c WHERE c.processed != true OR NOT IS_DEFINED(c.processed)',
                parameters: []
            };

            const { resources: items } = await container.items
                .query(querySpec, { maxItemCount: -1 })
                .fetchAll();

            context.log(`Found ${items.length} items to process`);

            if (items.length === 0) {
                return {
                    status: 200,
                    jsonBody: {
                        message: 'No items to process',
                        results: {
                            ...results,
                            status: 'completed',
                            endTime: new Date().toISOString(),
                            duration: Date.now() - startTime
                        }
                    }
                };
            }

            const batches = [];
            for (let i = 0; i < items.length; i += BATCH_SIZE) {
                batches.push(items.slice(i, i + BATCH_SIZE));
            }

            results.totalBatches = batches.length;

            for (let batchIndex = 0; batchIndex < batches.length; batchIndex++) {
                const elapsed = Date.now() - startTime;
                if (elapsed > MAX_EXECUTION_TIME) {
                    context.log('Approaching timeout limit, stopping gracefully');
                    results.status = 'partial';
                    break;
                }

                const batch = batches[batchIndex];
                context.log(`Processing batch ${batchIndex + 1}/${batches.length}`);

                const batchPromises = batch.map(async (item) => {
                    try {
                        const processedItem = await processItem(item, context);
                        
                        processedItem.processed = true;
                        processedItem.processedAt = new Date().toISOString();
                        
                        await container.item(processedItem.id, processedItem.partitionKey || processedItem.id)
                            .replace(processedItem);
                        
                        results.processed++;
                        return { success: true, id: item.id };
                    } catch (error) {
                        results.failed++;
                        results.errors.push({
                            id: item.id,
                            error: error.message,
                            timestamp: new Date().toISOString()
                        });
                        context.error(`Error processing item ${item.id}:`, error);
                        return { success: false, id: item.id, error: error.message };
                    }
                });

                await Promise.allSettled(batchPromises);

                if ((batchIndex + 1) % 10 === 0) {
                    context.log(`Progress: ${results.processed} processed, ${results.failed} failed`);
                }
            }

            results.status = results.processed === items.length ? 'completed' : 'partial';
            results.endTime = new Date().toISOString();
            results.duration = Date.now() - startTime;

            context.log('Batch processing completed', results);

            return {
                status: 200,
                jsonBody: {
                    message: 'Batch processing completed',
                    results: results
                }
            };

        } catch (error) {
            context.error('Critical error in batch processing:', error);
            results.status = 'failed';
            results.endTime = new Date().toISOString();
            results.duration = Date.now() - startTime;
            results.errors.push({
                type: 'critical',
                error: error.message,
                stack: error.stack,
                timestamp: new Date().toISOString()
            });

            return {
                status: 500,
                jsonBody: {
                    message: 'Batch processing failed',
                    error: error.message,
                    results: results
                }
            };
        }
    }
});

