async function processItem(item, context) {
    await new Promise(resolve => setTimeout(resolve, 10));
    
    const processed = {
        ...item,
        transformedData: transformData(item),
        validationResult: validateData(item),
        enrichedData: await enrichData(item, context)
    };

    return processed;
}

function transformData(item) {
    const transformed = {};
    
    for (const [key, value] of Object.entries(item)) {
        if (typeof value === 'string') {
            transformed[key] = value.trim().toUpperCase();
        } else if (typeof value === 'number') {
            transformed[key] = value * 1.1;
        } else {
            transformed[key] = value;
        }
    }
    
    return transformed;
}

function validateData(item) {
    const validations = {
        hasId: !!item.id,
        hasRequiredFields: true,
        validFormat: true,
        errors: []
    };

    if (!item.id) {
        validations.errors.push('Missing ID');
    }

    return validations;
}

async function enrichData(item, context) {
    await new Promise(resolve => setTimeout(resolve, 5));
    
    return {
        processingTimestamp: new Date().toISOString(),
        processingVersion: '1.0.0',
        metadata: {
            source: 'batch-processor',
            itemCount: 1
        }
    };
}

app.http('batchProcessorStatus', {
    methods: ['GET'],
    authLevel: 'function',
    handler: async (request, context) => {
        try {
            const querySpec = {
                query: 'SELECT VALUE COUNT(1) FROM c WHERE c.processed = true'
            };
            
            const { resources: [processedCount] } = await container.items
                .query(querySpec)
                .fetchAll();

            const unprocessedQuery = {
                query: 'SELECT VALUE COUNT(1) FROM c WHERE c.processed != true OR NOT IS_DEFINED(c.processed)'
            };
            
            const { resources: [unprocessedCount] } = await container.items
                .query(unprocessedQuery)
                .fetchAll();

            return {
                status: 200,
                jsonBody: {
                    processed: processedCount,
                    unprocessed: unprocessedCount,
                    total: processedCount + unprocessedCount,
                    timestamp: new Date().toISOString()
                }
            };

        } catch (error) {
            context.error('Error getting status:', error);
            return {
                status: 500,
                jsonBody: {
                    error: error.message
                }
            };
        }
    }
});